// // This module compares two 4-bit inputs and outputs a low signal on EQ if they are equal, and a low signal on GT if in0 is greater than in1.
module top_module(
    input [3:0] in0,
    input [3:0] in1,
    output EQ,
    output GT
);assign EQ = (in0 == in1) ? 1'b1 : 1'b0;
    assign GT = (in0 > in1) ? 1'b1 : 1'b0;

endmodule
